using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
const int N = 1005;
int n, c;
long long a[N], sum[N], maxn = 0;
void dfs(int idx, long long current)
{
	if (current > c) return;
	if (idx == 0)
	{
		maxn = max(maxn, current);
		return;
	}
	if (current + sum[idx] <= maxn) return;
	if (current + sum[idx] <= c)
	{
		maxn = max(maxn, current + sum[idx]);
		return;
	}
	if (current + a[idx] <= c)
		dfs(idx - 1, current + a[idx]);
	dfs(idx - 1, current);
}
int main()
{
	cin >> n >> c;
	for (int i = 1 ; i <= n ; i++)
	{
		cin >> a[i];
		sum[i] = sum[i - 1] + a[i];
	}
	dfs(n, 0);
	cout << maxn;
	return 0;
}
